using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerResourceType]
public class ConfigResource
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "AppSettings")]
    [Description("Returns the current application configuration as JSON")]
    public static string GetSettings()
    {
        var config = new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            MaxConnections = 100,
            EnableLogging = true,
            SupportedRegions = new[] { "us-east-1", "eu-west-1", "ap-southeast-1" }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/features/{featureName}", Name = "FeatureFlag")]
    [Description("Returns the status of a specific feature flag")]
    public static string GetFeatureFlag(string featureName)
    {
        var features = new Dictionary<string, bool>
        {
            ["dark-mode"] = true,
            ["beta-dashboard"] = false,
            ["new-auth-flow"] = true,
        };

        var enabled = features.TryGetValue(featureName, out var value) && value;

        return JsonSerializer.Serialize(new { Feature = featureName, Enabled = enabled });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpHttpServer;

[McpServerToolType]
public class EchoTool
{
    [McpServerTool(Name = "echo"), Description("Echoes back the provided message")]
    public static string Echo(string message) => $"Echo: {message}";

    [McpServerTool(Name = "get_time"), Description("Returns the current server time in UTC")]
    public static string GetTime() => DateTime.UtcNow.ToString("o");
}

